 1	import * as React from 'react';
 2	import { Split, SplitItem, Divider } from '@patternfly/react-core';
 3	import cx from 'classnames';
 4	import { CatalogItem } from '@openshift-console/dynamic-plugin-sdk';
 5	import QuickSearchDetails, {
 6	  DetailsRendererFunction,
 7	} from './QuickSearchDetails';
 8	import QuickSearchList from './QuickSearchList';
 9	import { CatalogLinkData } from './utils/quick-search-types';
10	import { CatalogType } from '../catalog/types';
11	import { TaskSearchCallback } from '../pipeline-builder/types';
12	import './QuickSearchContent.scss';
13	
14	interface QuickSearchContentProps {
15	  catalogItems: CatalogItem[];
16	  catalogItemTypes: CatalogType[];
17	  searchTerm: string;
18	  namespace: string;
19	  selectedItemId: string;
20	  selectedItem: CatalogItem;
21	  limitItemCount?: number;
22	  onSelect: (itemId: string) => void;
23	  viewAll?: CatalogLinkData[];
24	  closeModal: () => void;
25	  detailsRenderer?: DetailsRendererFunction;
26	  onListChange?: (items: number) => void;
27	  callback?: TaskSearchCallback;
28	  setFailedTasks?: React.Dispatch<React.SetStateAction<string[]>>;
29	}
30	
31	const QuickSearchContent: React.FC<QuickSearchContentProps> = ({
32	  catalogItems,
33	  catalogItemTypes,
34	  viewAll,
35	  searchTerm,
36	  namespace,
37	  selectedItem,
38	  selectedItemId,
39	  onSelect,
40	  closeModal,
41	  limitItemCount,
42	  detailsRenderer,
43	  onListChange,
44	  callback,
45	  setFailedTasks,
46	}) => {
47	  return (
48	    <Split className="ocs-quick-search-content">
49	      <SplitItem
50	        className={cx('ocs-quick-search-content__list', {
51	          'ocs-quick-search-content__list--overflow':
52	            catalogItems.length >= limitItemCount,
53	        })}
54	      >
55	        <QuickSearchList
56	          listItems={catalogItems}
57	          limitItemCount={limitItemCount}
58	          catalogItemTypes={catalogItemTypes}
59	          viewAll={viewAll}
60	          selectedItemId={selectedItemId}
61	          searchTerm={searchTerm}
62	          namespace={namespace}
63	          onSelectListItem={(_event, itemId) => onSelect(itemId)}
64	          closeModal={closeModal}
65	          onListChange={onListChange}
66	        />
67	      </SplitItem>
68	      <Divider component="div" orientation={{ default: 'vertical' }} />
69	      <SplitItem className="ocs-quick-search-content__details">
70	        <QuickSearchDetails
71	          detailsRenderer={detailsRenderer}
72	          selectedItem={selectedItem}
73	          closeModal={closeModal}
74	          namespace={namespace}
75	          callback={callback}
76	          setFailedTasks={setFailedTasks}
77	        />
78	      </SplitItem>
79	    </Split>
80	  );
81	};
82	
83	export default QuickSearchContent;

